+                .to_owned(),
+            category: CorruptionCategory::DatabaseFile,
+            severity: CorruptionSeverity::Moderate,
+            default_seed: 42,
+            pattern: CorruptionPattern::BitFlipMany {
+                offset: 4096,
+                length: 512,
+                count: 8,
+                seed: 42,
+            },
+        },
+        CatalogEntry {
+            strategy_id: "truncate_db_half".to_owned(),
