+        let result = measure_sqlite3_baseline(entry, dir.path()).unwrap();
+
+        assert_eq!(result.strategy_id, "sidecar_corrupt_symbols");
+        // sqlite3 ignores FEC sidecars — should open and match.
+        assert_eq!(
